// Main
// ============================================================================

int main() {
    UNITY_BEGIN();

    // Basic tests
    RUN_TEST(test_ekf6_initialization);
    RUN_TEST(test_ekf6_initialization_with_attitude);
    RUN_TEST(test_ekf6_state_accessors);

    // Attitude estimation tests
    RUN_TEST(test_ekf6_level_flight);
    RUN_TEST(test_ekf6_pitched_10deg);
    RUN_TEST(test_ekf6_banked_20deg);
    RUN_TEST(test_ekf6_pitch_rate_integration);
    RUN_TEST(test_ekf6_gyro_bias_estimation);

    // Numerical stability tests
    RUN_TEST(test_ekf6_no_nan_output);
    RUN_TEST(test_ekf6_zero_dt_handling);
    RUN_TEST(test_ekf6_large_attitude_stability);

    // Configuration test
    RUN_TEST(test_ekf6_custom_config);

    // Alpha covariance reset tests
    RUN_TEST(test_ekf6_reset_alpha_covariance_basic);
    RUN_TEST(test_ekf6_stale_alpha_without_reset);
    RUN_TEST(test_ekf6_reset_alpha_covariance_uninitialized);
    RUN_TEST(test_ekf6_reset_preserves_other_states);

    // dt-scaling: Q is treated as continuous-time spectral density
    // and integrated as Q*dt per step.
    RUN_TEST(test_ekf6_q_units_continuous_time_density);
    RUN_TEST(test_ekf6_dt_scaling_preserves_208hz_static_tilt);

    // Bias estimator converges fast enough that a real-world gyro
    // bias is fully learned within typical pre-takeoff time (#128).
    RUN_TEST(test_ekf6_ground_bias_convergence_with_realistic_gyro_bias);

    // Filter separates attitude from bias when both are non-zero.
    RUN_TEST(test_ekf6_disentangles_attitude_from_bias);

    // The chosen q_bias holds up under realistic accel noise;
    // confirms the "moderate" choice over more-aggressive values.
    RUN_TEST(test_ekf6_qbias_choice_holds_under_realistic_accel_noise);

    return UNITY_END();
}
